#define MAX_WIFI_COUNT 20

static const char *TAG = "APPSeeting_Event";

static char selected_ssid[33] = {0};
static wifi_ap_record_t g_ap_list[MAX_WIFI_COUNT];
static uint16_t g_ap_count = 0;
static bool is_scanning = false; 
static bool is_connecting = false;
// 连接结果（由WiFi事件回调设置）
static bool wifi_connected_result = false;
