void ScanWIFI(lv_event_t * e)
{
	if (is_scanning) {
        btn_create("Wait...");
        return;
    }
	is_scanning = true;
	
	esp_err_t scan_ret = wifi_manager_scan(wifi_scan_callback);
    if (scan_ret == ESP_OK)
    {
        btn_create("Scanning...");
        ESP_LOGI(TAG, "WiFi 扫描任务已启动");
    }
    else
    {
		btn_create("try again");
        ESP_LOGE(TAG, "启动 WiFi 扫描失败");
		is_scanning = false;
    }
}

